s = criteria.meetCriteria(persons); return otherCriteria.meetCriteria(firstCriteriaPersons); &#125;&#125;class OrCriteria implements Criteria &#123; Criteria criteria; Criteria otherCriteria; public OrCriteria(Criteria criteria, Criteria otherCriteria) &#123; this.criteria = criteria; this.otherCriteria = otherCriteria; &#125; @Override public List&lt;Person&gt; meetCriteria(List&lt;Person&gt; persons) &#123; List&lt;Person&gt; firstCriteriaItems = criteria.meetCriteria(persons); List&lt;Person&gt; otherCriteriaItems = otherCriteria.meetCriteria(persons); for (Person person : otherCriteriaItems) &#123; if (!firstCriteriaItems.contains(person)) &#123; firstCriteriaItems.add(person); &#125; &#125; return firstCriteriaItems; &#125;&#125;public class CriteriaPatternDemo &#123; public static void main(String[] args) &#123; List&lt;Person&gt; persons = new ArrayList&lt;&gt;(); persons.add(new Person(&quot;Robert&quot;, &quot;Male&quot;, &quot;Single&quot;)); persons.add(new Person(&quot;John&quot;, &quot;Male&quot;, &quot;Married&quot;)); persons.add(new Person(&quot;Laura&quot;, &quot;Female&quot;, &quot;Married&quot;)); persons.add(new Person(&quot;Diana&quot;, &quot;Female&quot;, &quot;Single&quot;)); persons.add(new Person(&quot;Mike&quot;, &quot;Male&quot;, &quot;Single&quot;)); persons.add(new Person(&quot;Bobby&quot;, &quot;Male&quot;, &quot;Single&quot;)); Criteria male = new CriteriaMale(); Criteria female = new CriteriaFemale(); Criteria single = new CriteriaSingle(); Criteria singleMale = new AndCriteria(single, male); Criteria singleOrFemale = new OrCriteria(single, female); System.out.println(&quot;Males: &quot;); printPersons(male.meetCriteria(persons)); System.out.println(&quot;
